from difflib import SequenceMatcher

def fuzzy_match(name: str, existing_names: list[str], threshold: float = 0.85) -> str | None:
    """Return the best-matching existing name if similarity >= threshold."""
    best, best_score = None, 0.0
    for existing in existing_names:
        score = SequenceMatcher(None, name.lower(), existing.lower()).ratio()
        if score > best_score:
            best, best_score = existing, score
    return best if best_score >= threshold else None

def resolve_entity(name: str, graph: Neo4jGraph) -> str:
    existing = [
        r["n.name"]
        for r in graph.query("MATCH (n) RETURN n.name LIMIT 1000")
        if r.get("n.name")
    ]
    resolved = fuzzy_match(name, existing)
    return resolved if resolved else name

def insert_triple_with_resolution(triple: Triple, graph: Neo4jGraph) -> None:
    resolved_subj = resolve_entity(triple.subject, graph)
    resolved_obj = resolve_entity(triple.obj, graph)
    graph.query(
        """
        MERGE (s {name: $subject, type: $subject_type})
        MERGE (o {name: $obj, type: $object_type})
        MERGE (s)-[r:RELATION {predicate: $predicate}]->(o)
        """,
        {
            "subject": resolved_subj,
            "subject_type": triple.subject_type,
            "obj": resolved_obj,
            "object_type": triple.object_type,
            "predicate": triple.predicate,
        },
    )

from dataclasses import dataclass

@dataclass
class TripleKey:
    subject: str
    predicate: str
    obj: str

    def normalised(self) -> "TripleKey":
        return TripleKey(
            subject=self.subject.lower().strip(),
            predicate=self.predicate.lower().strip(),
            obj=self.obj.lower().strip(),
        )

def evaluate_extraction(
    predicted: list[Triple],
    gold: list[Triple],
) -> dict[str, float]:
    pred_set = {TripleKey(t.subject, t.predicate, t.obj).normalised() for t in predicted}
    gold_set = {TripleKey(t.subject, t.predicate, t.obj).normalised() for t in gold}

    tp = len(pred_set & gold_set)
    precision = tp / len(pred_set) if pred_set else 0.0
    recall = tp / len(gold_set) if gold_set else 0.0
    f1 = 2 * precision * recall / (precision + recall + 1e-9)
    return {"precision": precision, "recall": recall, "f1": f1}

